{
  "$schema": "https://schema.management.azure.com/providers/Microsoft.Logic/schemas/2016-06-01/workflowdefinition.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "$connections":    { "type": "Object", "defaultValue": {} },
    "appBaseUrl":      { "type": "string" },
    "tierCallbackUrl": { "type": "string" },
    "teamsWebhookUrl": { "type": "string", "defaultValue": "" },
    "notifyFromEmail": { "type": "string", "defaultValue": "" }
  },
  "triggers": {
    "manual": {
      "type": "Request",
      "kind": "Http",
      "inputs": {
        "schema": {
          "type": "object",
          "properties": {
            "requestId":            { "type": "string" },
            "workflowDefinitionId": { "type": "string" },
            "currentTierNumber":    { "type": "integer" },
            "approverEmails":       { "type": "string" },
            "approverType":         { "type": "string" },
            "documentUrl":          { "type": "string" },
            "tierName":             { "type": "string" },
            "title":                { "type": "string" },
            "requestedBy":          { "type": "string" }
          }
        }
      }
    }
  },
  "actions": {
    "Register_Callback": {
      "type": "Http",
      "runAfter": {},
      "inputs": {
        "method": "POST",
        "uri": "@{parameters('tierCallbackUrl')}",
        "headers": { "Content-Type": "application/json" },
        "body": {
          "approvalRequestId": "@{triggerBody()?['requestId']}",
          "tierNumber": "@{triggerBody()?['currentTierNumber']}",
          "callbackUrl": "@{listCallbackUrl()}"
        }
      }
    },
    "Send_Approval_Email": {
      "type": "ApiConnection",
      "runAfter": { "Register_Callback": ["Succeeded"] },
      "inputs": {
        "host": {
          "connection": { "name": "@parameters('$connections')['office365']['connectionId']" }
        },
        "method": "post",
        "path": "/v2/Mail",
        "body": {
          "To":         "@{triggerBody()?['approverEmails']}",
          "Subject":    "Action Required: @{triggerBody()?['title']} — @{triggerBody()?['tierName']}",
          "Body":       "<p>You have been requested to review and approve a document in <strong>Approvals Demo</strong>.</p><table><tr><td><strong>Document:</strong></td><td>@{triggerBody()?['title']}</td></tr><tr><td><strong>Approval Stage:</strong></td><td>@{triggerBody()?['tierName']}</td></tr><tr><td><strong>Submitted by:</strong></td><td>@{triggerBody()?['requestedBy']}</td></tr></table><p><a href=\"@{triggerBody()?['documentUrl']}\">Click here to review and approve</a></p><p>This link is unique to you. Do not share it.</p>",
          "Importance": "High",
          "IsHtml":     true
        }
      }
    },
    "Send_Teams_Notification": {
      "type": "Http",
      "runAfter": { "Register_Callback": ["Succeeded"] },
      "inputs": {
        "method": "POST",
        "uri":    "@{parameters('teamsWebhookUrl')}",
        "headers": { "Content-Type": "application/json" },
        "body": {
          "messageTitle":   "Approval Required",
          "title":          "@{triggerBody()?['title']}",
          "tierName":       "@{triggerBody()?['tierName']}",
          "approverEmails": "@{triggerBody()?['approverEmails']}",
          "requestedBy":    "@{triggerBody()?['requestedBy']}",
          "reviewUrl":      "@{triggerBody()?['documentUrl']}"
        }
      }
    },
    "Log_Notification": {
      "type": "Http",
      "runAfter": {
        "Send_Approval_Email":      ["Succeeded", "Failed"],
        "Send_Teams_Notification":  ["Succeeded", "Failed"]
      },
      "inputs": {
        "method": "POST",
        "uri": "@{parameters('appBaseUrl')}/api/approval/log-reminder",
        "headers": { "Content-Type": "application/json" },
        "body": {
          "tierProgressId": "@{body('Register_Callback')?['tierProgressId']}",
          "approverEmail":  "@{split(triggerBody()?['approverEmails'], ';')[0]}"
        }
      }
    },
    "Wait_For_Decision": {
      "type": "HttpWebhook",
      "runAfter": { "Log_Notification": ["Succeeded", "Failed"] },
      "inputs": {
        "subscribe": {
          "method": "GET",
          "uri": "@{parameters('appBaseUrl')}/noop"
        },
        "unsubscribe": {}
      }
    },
    "Check_Decision": {
      "type": "Switch",
      "runAfter": { "Wait_For_Decision": ["Succeeded"] },
      "expression": "@body('Wait_For_Decision')?['decision']",
      "cases": {
        "Advance": {
          "case": "advance",
          "actions": {
            "Register_Next_Callback": {
              "type": "Http",
              "runAfter": {},
              "inputs": {
                "method": "POST",
                "uri": "@{parameters('tierCallbackUrl')}",
                "headers": { "Content-Type": "application/json" },
                "body": {
                  "approvalRequestId": "@{triggerBody()?['requestId']}",
                  "tierNumber":        "@{body('Wait_For_Decision')?['nextTierData']?['tierNumber']}",
                  "callbackUrl":       "@{listCallbackUrl()}"
                }
              }
            },
            "Send_Next_Tier_Email": {
              "type": "ApiConnection",
              "runAfter": { "Register_Next_Callback": ["Succeeded"] },
              "inputs": {
                "host": {
                  "connection": { "name": "@parameters('$connections')['office365']['connectionId']" }
                },
                "method": "post",
                "path": "/v2/Mail",
                "body": {
                  "To":         "@{body('Wait_For_Decision')?['nextTierData']?['approverEmails']}",
                  "Subject":    "Action Required: @{triggerBody()?['title']} — @{body('Wait_For_Decision')?['nextTierData']?['tierName']}",
                  "Body":       "<p>You have been requested to review and approve a document in <strong>Approvals Demo</strong>.</p><table><tr><td><strong>Document:</strong></td><td>@{triggerBody()?['title']}</td></tr><tr><td><strong>Approval Stage:</strong></td><td>@{body('Wait_For_Decision')?['nextTierData']?['tierName']}</td></tr><tr><td><strong>Submitted by:</strong></td><td>@{triggerBody()?['requestedBy']}</td></tr></table><p><a href=\"@{body('Wait_For_Decision')?['nextTierData']?['documentUrl']}\">Click here to review and approve</a></p>",
                  "Importance": "High",
                  "IsHtml":     true
                }
              }
            },
            "Send_Next_Tier_Teams": {
              "type": "Http",
              "runAfter": { "Register_Next_Callback": ["Succeeded"] },
              "inputs": {
                "method": "POST",
                "uri":    "@{parameters('teamsWebhookUrl')}",
                "headers": { "Content-Type": "application/json" },
                "body": {
                  "messageTitle":   "Approval Required — Next Stage",
                  "title":          "@{triggerBody()?['title']}",
                  "tierName":       "@{body('Wait_For_Decision')?['nextTierData']?['tierName']}",
                  "approverEmails": "@{body('Wait_For_Decision')?['nextTierData']?['approverEmails']}",
                  "requestedBy":    "@{triggerBody()?['requestedBy']}",
                  "reviewUrl":      "@{body('Wait_For_Decision')?['nextTierData']?['documentUrl']}"
                }
              }
            }
          }
        },
        "Complete": {
          "case": "complete",
          "actions": {}
        }
      },
      "default": { "actions": {} }
    },
    "Return_200": {
      "type": "Response",
      "runAfter": { "Check_Decision": ["Succeeded", "Skipped"] },
      "inputs": { "statusCode": 200 }
    }
  },
  "outputs": {}
}

